    let random=Math.floor(Math.random()*3)
    return name[random]
  }
  return (
   <main>
     <p>
      Let move on to grow based on {name}
      <button onClick={()=>handleClick()}>Subscribe </button>
    </p>
   </main>
  )
}

export default Content
